@startuml
title 接口隔离原则

class "C A" {
  <<Class>>
}

class "C B" {
  <<Class>>
}

class "C C" {
  <<Class>>
}

class "C D" {
  <<Class>>
}

interface "Interface2" {
  operation2():void
  operation3():void
}

interface "Interface1" {
  operation1():void
}

interface "Interface3" {
  operation4():void
  operation5():void
}

"C A" ..> "Interface2"
"C B" ..> "Interface1"
"C C" ..> "Interface1"
"C D" ..> "Interface3"

"C A" --|> "Interface2"
"C B" --|> "Interface1"
"C C" --|> "Interface1"
"C D" --|> "Interface3"

@enduml
